from __future__ import annotations

from collections.abc import Iterable, Mapping

from report_app.models import Incident, OwnerLoad, TriageSummary


def summarize_incidents(
    incidents: Iterable[Incident],
    *,
    ack_sla_minutes: Mapping[str, int],
) -> TriageSummary:
    incident_list = list(incidents)
    owner_totals: dict[str, dict[str, int | str]] = {}
    breached_count = 0

    for incident in incident_list:
        breached = incident.is_ack_sla_breached(ack_sla_minutes)
        breached_count += int(breached)
        row = owner_totals.setdefault(
            incident.owner,
            {
                "owner": incident.owner,
                "count": 0,
                "breached": 0,
            },
        )
        row["count"] = int(row["count"]) + 1
        row["breached"] = int(row["breached"]) + int(breached)

    owner_load = tuple(
        OwnerLoad(
            owner=str(row["owner"]),
            count=int(row["count"]),
            breached=int(row["breached"]),
        )
        for row in sorted(
            owner_totals.values(),
            key=lambda item: (-int(item["count"]), -int(item["breached"]), str(item["owner"]).lower()),
        )
    )
    highest_load_owner = owner_load[0].as_dict() if owner_load else None
    return TriageSummary(
        incident_count=len(incident_list),
        breached_count=breached_count,
        highest_load_owner=highest_load_owner,
        owner_load=owner_load,
    )

from __future__ import annotations

from dataclasses import dataclass
from typing import Mapping


@dataclass(frozen=True)
class Incident:
    service: str
    severity: str
    owner: str
    minutes_open: int
    acked: bool

    @classmethod
    def from_mapping(cls, payload: Mapping[str, object]) -> "Incident":
        return cls(
            service=str(payload["service"]),
            severity=str(payload["severity"]),
            owner=str(payload["owner"]),
            minutes_open=int(payload["minutes_open"]),
            acked=bool(payload["acked"]),
        )

    def as_dict(self) -> dict[str, object]:
        return {
            "service": self.service,
            "severity": self.severity,
            "owner": self.owner,
            "minutes_open": self.minutes_open,
            "acked": self.acked,
        }

    def is_ack_sla_breached(self, sla_minutes: Mapping[str, int]) -> bool:
        if self.acked:
            return False
        return self.minutes_open > int(sla_minutes[self.severity])


@dataclass(frozen=True)
class OwnerLoad:
    owner: str
    count: int
    breached: int

    def as_dict(self) -> dict[str, object]:
        return {
            "owner": self.owner,
            "count": self.count,
            "breached": self.breached,
        }


@dataclass(frozen=True)
class TriageSummary:
    incident_count: int
    breached_count: int
    highest_load_owner: dict[str, object] | None
    owner_load: tuple[OwnerLoad, ...]

    def as_dict(self) -> dict[str, object]:
        return {
            "incident_count": self.incident_count,
            "breached_count": self.breached_count,
            "highest_load_owner": self.highest_load_owner,
            "owner_load": [entry.as_dict() for entry in self.owner_load],
        }
